sys_script_include.script:
var UserDetailFetcher = Class.create();
UserDetailFetcher.prototype = Object.extendsObject(global.AbstractAjaxProcessor, { // Added 'global.' prefix

    getDisplayValues: function() {
        var userId = this.getParameter('sysparm_user_id');
        var userGR = new GlideRecord('sys_user');
        var result = {};

        if (userGR.get(userId)) {
            // .getDisplayValue() returns the Name instead of the sys_id
            result.company = userGR.company.getDisplayValue() || 'N/A';
            result.department = userGR.department.getDisplayValue() || 'N/A';
            result.email = userGR.getValue('email') || 'N/A';
            result.mobile = userGR.getValue('mobile_phone') || 'N/A';
            result.title = userGR.getValue('title') || 'N/A';
        }
        return JSON.stringify(result);
    },

    type: 'UserDetailFetcher'
});
